class Board:
    def __init__(self):
        self.board = self.create_board()

    def create_board(self):
        # Initialize an 8x8 board with pieces in the starting positions
        board = []
        for row in range(8):
            if row < 3:
                board.append(['b' if col % 2 == 1 else None for col in range(8)])
            elif row > 4:
                board.append(['r' if col % 2 == 0 else None for col in range(8)])
            else:
                board.append([None] * 8)
        return board

    def print_board(self):
        # Print the current state of the board
        for row in self.board:
            print(" ".join(row or []))
```

